import React from "react";

const AdminOrders = () => {
  const orders = [
    { id: 101, user: "John", total: "RM 250", status: "Paid" },
    { id: 102, user: "Sara", total: "RM 120", status: "Pending" },
  ];

  return (
    <>
      <h1>Orders</h1>

      <table className="admin-table">
        <thead>
          <tr>
            <th>Order ID</th>
            <th>User</th>
            <th>Total</th>
            <th>Status</th>
          </tr>
        </thead>

        <tbody>
          {orders.map((o) => (
            <tr key={o.id}>
              <td>{o.id}</td>
              <td>{o.user}</td>
              <td>{o.total}</td>
              <td>{o.status}</td>
            </tr>
          ))}
        </tbody>
      </table>
    </>
  );
};

export default AdminOrders;
